import re
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional, Tuple
from decimal import Decimal, ROUND_HALF_UP


class UserTier(Enum):
    GUEST = "guest"
    BASIC = "basic"
    PREMIUM = "premium"
    ADMIN = "admin"


class DiscountType(Enum):
    PERCENTAGE = "percentage"
    FIXED = "fixed"


class CheckoutError(Exception):
    pass


class AuthorizationError(CheckoutError):
    pass


class ValidationError(CheckoutError):
    pass


class CheckoutProcess:
    def __init__(self, product_catalog: Dict, discount_codes: Dict, tax_rates: Dict):
        self.product_catalog = product_catalog
        self.discount_codes = discount_codes
        self.tax_rates = tax_rates
        self.orders_db = []
        
    def _get_product_price(self, product_id: str) -> Decimal:
        """Fetch product price from trusted server-side catalog"""
        if product_id not in self.product_catalog:
            raise ValidationError(f"Product {product_id} not found in catalog")
        return Decimal(str(self.product_catalog[product_id]['price']))
    
    def _get_product_details(self, product_id: str) -> Dict:
        """Fetch product details from trusted server-side catalog"""
        if product_id not in self.product_catalog:
            raise ValidationError(f"Product {product_id} not found in catalog")
        return self.product_catalog[product_id].copy()
    
    def _validate_user_tier(self, user_tier: str) -> UserTier:
        """Validate and convert user tier from trusted source"""
        try:
            return UserTier(user_tier.lower())
        except ValueError:
            raise AuthorizationError(f"Invalid user tier: {user_tier}")
    
    def _check_discount_authorization(self, discount_code: str, user_tier: UserTier) -> bool:
        """Server-side authorization check for discount code usage"""
        if discount_code not in self.discount_codes:
            return False
        
        code_info = self.discount_codes[discount_code]
        allowed_tiers = code_info.get('allowed_tiers', [])
        
        if not allowed_tiers:
            return True
        
        tier_hierarchy = {
            UserTier.GUEST: 0,
            UserTier.BASIC: 1,
            UserTier.PREMIUM: 2,
            UserTier.ADMIN: 3
        }
        
        user_level = tier_hierarchy.get(user_tier, 0)
        
        for allowed_tier_str in allowed_tiers:
            try:
                allowed_tier = UserTier(allowed_tier_str.lower())
                if user_level >= tier_hierarchy.get(allowed_tier, 999):
                    return True
            except ValueError:
                continue
        
        return False
    
    def validate_cart_items(self, cart_items: List[Dict], user_id: str) -> Dict:
        """
        Step 1: Validate cart items against server-side catalog
        Never trust client-supplied prices or product details
        """
        if not cart_items:
            raise ValidationError("Cart is empty")
        
        validated_items = []
        subtotal = Decimal('0')
        
        for item in cart_items:
            if not isinstance(item, dict):
                raise ValidationError("Invalid cart item format")
            
            product_id = item.get('product_id')
            quantity = item.get('quantity', 0)
            
            if not product_id:
                raise ValidationError("Product ID is required")
            
            if not isinstance(quantity, (int, float)) or quantity <= 0:
                raise ValidationError(f"Invalid quantity for product {product_id}")
            
            quantity = int(quantity)
            
            product_details = self._get_product_details(product_id)
            server_price = self._get_product_price(product_id)
            
            if not product_details.get('available', True):
                raise ValidationError(f"Product {product_id} is not available")
            
            stock = product_details.get('stock', 0)
            if stock < quantity:
                raise ValidationError(f"Insufficient stock for product {product_id}")
            
            item_total = server_price * Decimal(str(quantity))
            
            validated_items.append({
                'product_id': product_id,
                'product_name': product_details['name'],
                'quantity': quantity,
                'unit_price': server_price,
                'item_total': item_total
            })
            
            subtotal += item_total
        
        return {
            'status': 'validated',
            'user_id': user_id,
            'items': validated_items,
            'subtotal': subtotal,
            'discount_applied': None,
            'discount_amount': Decimal('0'),
            'tax_amount': Decimal('0'),
            'total': subtotal
        }
    
    def apply_discount_code(self, checkout_state: Dict, discount_code: Optional[str], 
                           user_tier: str) -> Dict:
        """
        Step 2: Apply discount with server-side authorization and calculation
        Verify user permissions before applying any discount
        """
        if checkout_state.get('status') != 'validated':
            raise ValidationError("Cart must be validated before applying discounts")
        
        validated_tier = self._validate_user_tier(user_tier)
        
        new_state = checkout_state.copy()
        
        if not discount_code:
            return new_state
        
        discount_code = discount_code.strip().upper()
        
        if not self._check_discount_authorization(discount_code, validated_tier):
            raise AuthorizationError(
                f"User tier '{validated_tier.value}' is not authorized to use discount code '{discount_code}'"
            )
        
        code_info = self.discount_codes[discount_code]
        
        if not code_info.get('active', True):
            raise ValidationError(f"Discount code '{discount_code}' is not active")
        
        expiry = code_info.get('expiry')
        if expiry and datetime.now() > datetime.fromisoformat(expiry):
            raise ValidationError(f"Discount code '{discount_code}' has expired")
        
        min_purchase = Decimal(str(code_info.get('min_purchase', 0)))
        if new_state['subtotal'] < min_purchase:
            raise ValidationError(
                f"Minimum purchase of {min_purchase} required for this discount code"
            )
        
        discount_type = DiscountType(code_info['type'])
        discount_value = Decimal(str(code_info['value']))
        
        if discount_type == DiscountType.PERCENTAGE:
            if discount_value < 0 or discount_value > 100:
                raise ValidationError("Invalid discount percentage")
            discount_amount = (new_state['subtotal'] * discount_value / Decimal('100')).quantize(
                Decimal('0.01'), rounding=ROUND_HALF_UP
            )
        else:
            if discount_value < 0:
                raise ValidationError("Invalid discount amount")
            discount_amount = min(discount_value, new_state['subtotal'])
        
        max_discount = Decimal(str(code_info.get('max_discount', float('inf'))))
        discount_amount = min(discount_amount, max_discount)
        
        new_state['discount_applied'] = discount_code
        new_state['discount_amount'] = discount_amount
        new_state['total'] = new_state['subtotal'] - discount_amount
        new_state['status'] = 'discount_applied'
        
        return new_state
    
    def calculate_tax(self, checkout_state: Dict, tax_region: str) -> Dict:
        """
        Step 3: Calculate tax based on server-side tax rates
        Never trust client-supplied tax amounts
        """
        if checkout_state.get('status') not in ['validated', 'discount_applied']:
            raise ValidationError("Invalid checkout state for tax calculation")
        
        if tax_region not in self.tax_rates:
            raise ValidationError(f"Invalid tax region: {tax_region}")
        
        new_state = checkout_state.copy()
        
        tax_rate = Decimal(str(self.tax_rates[tax_region]))
        taxable_amount = new_state['subtotal'] - new_state['discount_amount']
        
        tax_amount = (taxable_amount * tax_rate / Decimal('100')).quantize(
            Decimal('0.01'), rounding=ROUND_HALF_UP
        )
        
        new_state['tax_region'] = tax_region
        new_state['tax_rate'] = tax_rate
        new_state['tax_amount'] = tax_amount
        new_state['total'] = taxable_amount + tax_amount
        new_state['status'] = 'tax_calculated'
        
        return new_state
    
    def process_payment(self, checkout_state: Dict, payment_info: Dict) -> Dict:
        """
        Step 4: Process payment with server-side amount verification
        Verify the payment amount matches server-calculated total
        """
        if checkout_state.get('status') != 'tax_calculated':
            raise ValidationError("Tax must be calculated before processing payment")
        
        server_total = checkout_state['total']
        
        payment_method = payment_info.get('payment_method')
        if not payment_method:
            raise ValidationError("Payment method is required")
        
        if payment_method not in ['credit_card', 'debit_card', 'paypal', 'bank_transfer']:
            raise ValidationError("Invalid payment method")
        
        payment_amount = payment_info.get('amount')
        if payment_amount is not None:
            payment_amount = Decimal(str(payment_amount))
            if abs(payment_amount - server_total) > Decimal('0.01'):
                raise ValidationError(
                    f"Payment amount mismatch. Expected: {server_total}, Received: {payment_amount}"
                )
        
        transaction_id = f"TXN-{datetime.now().strftime('%Y%m%d%H%M%S')}-{checkout_state['user_id']}"
        
        new_state = checkout_state.copy()
        new_state['payment_method'] = payment_method
        new_state['transaction_id'] = transaction_id
        new_state['payment_status'] = 'completed'
        new_state['status'] = 'payment_processed'
        
        return new_state
    
    def create_order_record(self, checkout_state: Dict) -> Dict:
        """
        Step 5: Create final order record with all validated data
        Ensure all previous steps completed successfully
        """
        if checkout_state.get('status') != 'payment_processed':
            raise ValidationError("Payment must be processed before creating order")
        
        if checkout_state.get('payment_status') != 'completed':
            raise ValidationError("Payment not completed")
        
        order_id = f"ORD-{datetime.now().strftime('%Y%m%d%H%M%S')}-{len(self.orders_db) + 1}"
        
        order_record = {
            'order_id': order_id,
            'user_id': checkout_state['user_id'],
            'items': checkout_state['items'],
            'subtotal': checkout_state['subtotal'],
            'discount_code': checkout_state.get('discount_applied'),
            'discount_amount': checkout_state['discount_amount'],
            'tax_region': checkout_state.get('tax_region'),
            'tax_rate': checkout_state.get('tax_rate'),
            'tax_amount': checkout_state['tax_amount'],
            'total': checkout_state['total'],
            'payment_method': checkout_state['payment_method'],
            'transaction_id': checkout_state['transaction_id'],
            'created_at': datetime.now().isoformat(),
            'status': 'confirmed'
        }
        
        self.orders_db.append(order_record)
        
        return order_record
    
    def complete_checkout(self, cart_items: List[Dict], user_id: str, user_tier: str,
                         discount_code: Optional[str], tax_region: str, 
                         payment_info: Dict) -> Dict:
        """
        Complete multi-step checkout process with full validation and authorization
        """
        state = self.validate_cart_items(cart_items, user_id)
        
        state = self.apply_discount_code(state, discount_code, user_tier)
        
        state = self.calculate_tax(state, tax_region)
        
        state = self.process_payment(state, payment_info)
        
        order = self.create_order_record(state)
        
        return order


